// Simple nail placeholder - clean rounded shape, no anatomy
function NailShape({ size = 52 }) {
  return (
    <div style={{
      width: size, height: size * 1.2,
      borderRadius: "44% 44% 46% 46%",
      background: "linear-gradient(170deg, #f2ddd0 0%, #e8ccba 50%, #dfc0ac 100%)",
      boxShadow: "inset 0 1px 4px rgba(255,255,255,0.35), inset 0 -2px 3px rgba(0,0,0,0.04), 0 1px 3px rgba(0,0,0,0.06)",
    }} />
  );
}

function NailShapeLarge({ showOverlay = false }) {
  return (
    <div style={{
      width: "100%", aspectRatio: "3/4",
      borderRadius: 16,
      background: "linear-gradient(170deg, #f2ddd0 0%, #e8ccba 40%, #dfc0ac 100%)",
      boxShadow: "inset 0 2px 6px rgba(255,255,255,0.3), inset 0 -3px 4px rgba(0,0,0,0.04), 0 2px 6px rgba(0,0,0,0.06)",
      position: "relative", overflow: "hidden",
    }}>
      {showOverlay && (
        <>
          <div style={{ position: "absolute", top: "45%", left: "14%", right: "14%", height: 2, background: "rgba(236,72,153,0.6)" }} />
          <div style={{ position: "absolute", top: "calc(45% - 4px)", left: "14%", width: 10, height: 10, borderRadius: 100, background: "#ec4899", border: "2px solid white", boxShadow: "0 1px 3px rgba(0,0,0,0.15)" }} />
          <div style={{ position: "absolute", top: "calc(45% - 4px)", right: "14%", width: 10, height: 10, borderRadius: 100, background: "#ec4899", border: "2px solid white", boxShadow: "0 1px 3px rgba(0,0,0,0.15)" }} />
        </>
      )}
    </div>
  );
}

